INSERT INTO blog_post_faqs (blog_post_id, question, answer, position)
VALUES 
  ('861446cd-42ae-4349-a0d0-95730ac7473e', 'Quelles sont les principales aides pour installer une pompe à chaleur en 2025 ?', 'Les principales aides sont MaPrimeRénov'' (de 3 000 à 11 000 € selon revenus), les Certificats d''Économies d''Énergie (CEE) ou Coup de pouce chauffage (2 500 à 5 000 €), la TVA réduite à 5,5 % et l''éco-prêt à taux zéro (éco-PTZ).', 1),
  ('861446cd-42ae-4349-a0d0-95730ac7473e', 'Les pompes à chaleur air-air sont-elles éligibles aux aides ?', 'Non, les PAC air-air (climatisations réversibles) sont généralement exclues de MaPrimeRénov'' et de la TVA à 5,5 %. Seules les pompes à chaleur air-eau et géothermiques sont éligibles aux principales aides.', 2),
  ('861446cd-42ae-4349-a0d0-95730ac7473e', 'Faut-il passer par un artisan RGE pour bénéficier des aides ?', 'Oui, pour bénéficier de MaPrimeRénov'', des CEE et de la TVA à 5,5 %, l''installation doit obligatoirement être réalisée par un professionnel certifié RGE (Reconnu Garant de l''Environnement).', 3),
  ('861446cd-42ae-4349-a0d0-95730ac7473e', 'Peut-on cumuler plusieurs aides pour une pompe à chaleur ?', 'Oui, il est possible de cumuler MaPrimeRénov'' avec les CEE, la TVA à 5,5 % et l''éco-PTZ. Certaines collectivités locales proposent également des aides complémentaires.', 4),
  ('861446cd-42ae-4349-a0d0-95730ac7473e', 'Comment faire une demande de MaPrimeRénov'' pour une pompe à chaleur ?', 'Créez un compte sur maprimerenov.gouv.fr, déposez votre demande avec les devis de l''artisan RGE, attendez l''accord, faites réaliser les travaux, puis téléchargez les factures pour recevoir le versement.', 5);